from cryptography.fernet import Fernet
from base64 import b64encode
import os

# Generate a new key and store it safely
def generate_key():
    key = Fernet.generate_key()
    return b64encode(key).decode("utf-8")  # Convert to base64 for storage

# Load the encryption key from config file or environment variable
def load_key():
    if 'ENCRYPTION_KEY' in os.environ:
        key = os.environ['ENCRYPTION_KEY']
    else:
        with open('encryption.key', 'rb') as key_file:
            key = key_file.read()
    return Fernet(key)

# Encrypt a credit card number
def encrypt_card_number(card_num):
    f = load_key()
    token = f.encrypt(card_num.encode("utf-8"))  # Convert to bytes before encryption
    return token.decode('utf-8')  # Return as base64 string for storage

# Decrypt a credit card number
def decrypt_card_number(token):
    f = load_key()
    encrypted_num = f.decrypt(token.encode("utf-8"))  # Convert from base64 to bytes before decryption
    return encrypted_num.decode('utf-8')  # Return as string for use in the application